const ConnectorIcon: React.FC<{ type: string, active: boolean }> = ({ type, active }) => {
  const config = CONNECTOR_PATHS[type as keyof typeof CONNECTOR_PATHS];
  if (!config) return null;
  const color = active ? 'var(--primary-color)' : '#bfbfbf';
  
  return (
    <svg width="40" height="34" viewBox={config.viewBox} fill="none" xmlns="http://www.w3.org/2000/svg">
      {config.paths.map((p, i) => (
        <path 
          key={i}
          d={p.d} 
          fill={p.fill || color} 
          fillRule={p.rule ? "evenodd" : undefined}
          clipRule={p.rule ? "evenodd" : undefined}
        />
      ))}
    </svg>
  );
};

